<script setup lang="ts">
import { computed,nextTick,onBeforeUnmount,onMounted,reactive,ref } from 'vue'
const props=withDefaults(defineProps<{initialView?:'image2d'|'model3d'|'review'}>(),{initialView:'image2d'})
const emit=defineEmits<{alert:[msg:string,type?:'success'|'error']}>()
const active=ref<'image2d'|'model3d'|'review'>(props.initialView),styles=ref<any[]>([]),assets=ref<any[]>([]),jobs=ref<any[]>([]),reviews=ref<any[]>([]),busy=ref(false)
const imageResult=ref<any>(null),tripoImageTimer=ref<any>(null),tripoImageProgress=ref(0),tripoImagePollFailures=ref(0),tripoConfigured=ref(true),tripoConfig=ref<any>({}),tripoProgress=ref(0),tripoStatus=ref(''),tripoPollFailures=ref(0),tripoTimer=ref<any>(null),imagePreviewUrl=ref(''),uploadPreviewUrl=ref(''),uploadLoadError=ref(''),imageLoadError=ref(''),resultAnchor=ref<HTMLElement|null>(null),aiStage=ref(''),elapsed=ref(0),stageTimer=ref<any>(null),modelResult=ref<any>(null),reviewResult=ref<any>(null),showReviewDetail=ref(false),reviewSubTab=ref<'new'|'history'>('new'),generatedPrompt=ref(''),uploadPreview=ref('')
const form2d=reactive({rawPrompt:'山城街巷主题文创钥匙扣，温暖治愈的城市插画风格，适合景区伴手礼',tripoImageModel:'seedream_v5',tripoTemplate:'',tPose:false,sketchToRender:false})
const form3d=reactive({mode:'image_to_model',modelVersion:'v3.1-20260211',rawPrompt:'山城街巷主题亚克力钥匙扣，异形轮廓，正面浮雕层次，适合打样和量产',prompt:'',negativePrompt:'低模、破面、错误拓扑、模糊纹理',inputAssetId:null as number|null,multiviewAssetIds:{front:null as number|null,left:null as number|null,back:null as number|null,right:null as number|null},exportFormats:'GLB',texture:true,pbr:true,textureQuality:'extreme',geometryQuality:'detailed',textureAlignment:'original_image',orientation:'align_image',autoSize:true,imageAutofix:true,quad:false,smartLowPoly:false,generateParts:false,exportUv:true,compress:false,faceLimit:2000000,modelSeed:null as number|null,imageSeed:null as number|null,textureSeed:null as number|null})
const tripoPreviews=reactive<Record<string,string>>({single:'',front:'',left:'',back:'',right:''})
const tripoModeLabel=computed(()=>form3d.mode==='text_to_model'?'文生3D':form3d.mode==='multiview_to_model'?'多视图生3D':'单图生3D')
const isP1=computed(()=>form3d.modelVersion==='tripo-p1')
const isLegacy25=computed(()=>form3d.modelVersion.includes('v2.5'))
const supportsAdvanced3d=computed(()=>!isP1.value&&!isLegacy25.value)
const max3dFaces=computed(()=>isP1.value?20000:isLegacy25.value?500000:form3d.quad?150000:form3d.smartLowPoly?20000:2000000)
const fallback3dModels=[{value:'tripo-p1',label:'P1.0 · P系列低面数旗舰',tag:'P SERIES',series:'P'},{value:'v3.1-20260211',label:'H3.1 · 最新高精度',tag:'LATEST',series:'H'},{value:'v3.0-20250812',label:'H3.0 · 稳定版',tag:'STABLE',series:'H'},{value:'v2.5-20250123',label:'H2.5 · 兼容版',tag:'LEGACY',series:'H'}]
const available3dModels=computed(()=>{const api=tripoConfig.value.modelOptions;return Array.isArray(api)&&api.length?api.map((x:any,i:number)=>({...x,tag:fallback3dModels.find(m=>m.value===x.value)?.tag||`MODEL ${i+1}`,series:x.series||fallback3dModels.find(m=>m.value===x.value)?.series||'H'})):fallback3dModels})
const selected3dModelLabel=computed(()=>available3dModels.value.find((x:any)=>x.value===form3d.modelVersion)?.label||form3d.modelVersion)
function select3dModel(model:string){if(busy.value)return;form3d.modelVersion=model;syncTripoCompatibility();modelResult.value=null;emit('alert',`已选择并连接 ${selected3dModelLabel.value}`,'success')}
const canGenerate3d=computed(()=>form3d.mode==='text_to_model'?!!form3d.prompt.trim():form3d.mode==='multiview_to_model'?!!form3d.multiviewAssetIds.front&&Object.values(form3d.multiviewAssetIds).filter(Boolean).length>=2:!!form3d.inputAssetId)
function syncTripoCompatibility(){if(isP1.value||isLegacy25.value){form3d.quad=false;form3d.smartLowPoly=false;form3d.generateParts=false}if(form3d.generateParts){form3d.quad=false;form3d.smartLowPoly=false;form3d.texture=false;form3d.pbr=false}if(form3d.quad){form3d.smartLowPoly=false;form3d.generateParts=false}else if(form3d.smartLowPoly){form3d.quad=false;form3d.generateParts=false}form3d.faceLimit=Math.max(isP1.value?48:1000,Math.min(Number(form3d.faceLimit||max3dFaces.value),max3dFaces.value));if(!form3d.texture)form3d.pbr=false}
const reviewForm=reactive({title:'新文创产品可行性评估',productType:'文创礼品',copy:'',targetAudience:'',priceRange:'',material:'',salesScene:'',productionRequirement:'',hotReference:'',competitorPrice:'',competitorSales:'',channelPlan:'景区/小红书/抖音/线下礼品店',targetCost:'',expectedVolume:'',assetId:null as number|null})
const imageAssets=computed(()=>assets.value.filter(x=>x.assetType==='image'))
const modelAssets=computed(()=>assets.value.filter(x=>x.assetType==='model'))
function showSavedModel(a:any){modelResult.value={assetId:a.id,modelUrl:a.fileUrl,previewUrl:a.previewUrl,format:a.format,taskId:a.assetNo,source:a.sourceType,saved:true};document.querySelector('.model-output')?.scrollIntoView({behavior:'smooth',block:'center'})}
function startStage(text:string){aiStage.value=text;elapsed.value=0;clearInterval(stageTimer.value);clearTimeout(tripoTimer.value);stageTimer.value=setInterval(()=>elapsed.value++,1000)}
function endStage(){clearInterval(stageTimer.value);clearTimeout(tripoTimer.value);stageTimer.value=null;aiStage.value=''}
function imageSrc(x:any){return imagePreviewUrl.value||(x?.imageUrl||x?.previewUrl||x?.fileUrl||'')}
async function prepareImagePreview(data:any){
  imageLoadError.value=''; if(!data?.assetId)throw new Error('生图接口未返回资产ID')
  let lastError:any=null
  for(let attempt=1;attempt<=6;attempt++){
    try{
      aiStage.value=`图片已生成，正在读取高清文件（第 ${attempt}/6 次）…`
      const response=await fetch(`/api/creative/ai/assets/${data.assetId}/content?v=${Date.now()}`,{cache:'no-store'})
      if(!response.ok)throw new Error(`图片读取失败 HTTP ${response.status}`)
      const blob=await response.blob(); if(!blob.type.startsWith('image/'))throw new Error(`图片接口返回类型异常：${blob.type||'unknown'}`)
      if(imagePreviewUrl.value.startsWith('blob:'))URL.revokeObjectURL(imagePreviewUrl.value)
      imagePreviewUrl.value=URL.createObjectURL(blob); await nextTick(); resultAnchor.value?.scrollIntoView({behavior:'smooth',block:'center'}); return
    }catch(e){lastError=e;if(attempt<6)await new Promise(resolve=>setTimeout(resolve,500*attempt))}
  }
  throw lastError
}
async function prepareUploadPreview(assetId:number){
  uploadLoadError.value=''; let lastError:any=null
  for(let attempt=1;attempt<=5;attempt++){
    try{
      const response=await fetch(`/api/creative/ai/assets/${assetId}/content?v=${Date.now()}`,{cache:'no-store'})
      if(!response.ok)throw new Error(`参考图读取失败 HTTP ${response.status}`)
      const blob=await response.blob(); if(!blob.type.startsWith('image/'))throw new Error(`参考图接口返回类型异常：${blob.type||'unknown'}`)
      if(uploadPreviewUrl.value.startsWith('blob:'))URL.revokeObjectURL(uploadPreviewUrl.value)
      uploadPreviewUrl.value=URL.createObjectURL(blob); return
    }catch(e){lastError=e;if(attempt<5)await new Promise(resolve=>setTimeout(resolve,300*attempt))}
  }
  uploadLoadError.value=lastError?.message||String(lastError);throw lastError
}
async function load(){try{const [s,a,j,r,t]=await Promise.all([fetch('/api/creative/ai/styles'),fetch('/api/creative/ai/assets'),fetch('/api/creative/ai/jobs'),fetch('/api/creative/ai/reviews'),fetch('/api/creative/ai/tripo/config')]);styles.value=await s.json();assets.value=await a.json();jobs.value=await j.json();reviews.value=await r.json();tripoConfig.value=await t.json();tripoConfigured.value=tripoConfig.value.configured;if(active.value==='model3d'&&!modelResult.value){const latest=assets.value.find(x=>x.assetType==='model');if(latest)showSavedModel(latest)}}catch(e:any){emit('alert','加载创意设计失败：'+e.message,'error')}}
async function compose(){if(!form2d.rawPrompt.trim()){emit('alert','请先填写基础创意描述','error');return}busy.value=true;startStage('正在调用 SiliconFlow · Qwen3，为 Tripo 文本生图整理优化提示词…');try{const r=await fetch('/api/creative/ai/prompt/tripo-optimize',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({prompt:form2d.rawPrompt})});if(!r.ok){const err=await r.json().catch(()=>null);throw new Error(err?.message||`HTTP ${r.status}`)}const d=await r.json();generatedPrompt.value=d.prompt||'';emit('alert','Qwen3提示词优化完成，可人工修改','success')}catch(e:any){emit('alert','提示词优化失败：'+e.message,'error')}finally{busy.value=false;endStage()}}
async function generate2d(){if(!generatedPrompt.value.trim())await compose();if(!generatedPrompt.value.trim())return;await generateTripo2d()}
async function generateTripo2d(){if(!tripoConfigured.value||!tripoConfig.value.serviceReachable){emit('alert','Tripo API当前不可用，请先检查配置','error');return}if(Number(tripoConfig.value.balance||0)<=0){emit('alert','Tripo API积分不足，无法提交文本生图','error');return}busy.value=true;imageResult.value=null;imageLoadError.value='';tripoImageProgress.value=0;tripoImagePollFailures.value=0;startStage(`正在调用 Tripo · ${form2d.tripoImageModel} 提交文本生图任务…`);try{const r=await fetch('/api/creative/ai/tripo/text-to-image',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({...form2d,prompt:generatedPrompt.value})});if(!r.ok){const err=await r.json().catch(()=>null);throw new Error(err?.message||`HTTP ${r.status}`)}const d=await r.json();emit('alert','Tripo文本生图任务已提交，后台会自动保存图片','success');await pollTripoImage(d.jobId)}catch(e:any){busy.value=false;endStage();emit('alert','Tripo文本生图失败：'+e.message,'error')}}
async function pollTripoImage(jobId:number){clearTimeout(tripoImageTimer.value);try{const r=await fetch(`/api/creative/ai/tripo/image-tasks/${jobId}`,{cache:'no-store'});if(!r.ok){const err=await r.json().catch(()=>null);throw new Error(err?.message||`HTTP ${r.status}`)}const d=await r.json();tripoImagePollFailures.value=0;tripoImageProgress.value=Number(d.progress||0);aiStage.value=d.status==='succeeded'?'Tripo图片生成完成，服务器已自动保存，正在加载高清图片…':`Tripo ${form2d.tripoImageModel} 正在生成图片 · ${tripoImageProgress.value||'等待'}%`;if(d.status==='succeeded'){imageResult.value=d;await prepareImagePreview(d);busy.value=false;endStage();emit('alert','Tripo文本生图完成并已自动保存','success');await load();return}if(d.status==='failed')throw new Error(d.errorMessage||'Tripo生图任务失败');tripoImageTimer.value=setTimeout(()=>pollTripoImage(jobId),2500)}catch(e:any){tripoImagePollFailures.value++;if(tripoImagePollFailures.value<=12){aiStage.value=`页面查询失败：${e.message}；服务器后台仍在自动保存，5秒后重试（${tripoImagePollFailures.value}/12）…`;tripoImageTimer.value=setTimeout(()=>pollTripoImage(jobId),5000);return}busy.value=false;endStage();emit('alert','页面查询多次失败；后台仍会继续保存，可稍后刷新资产库。原因：'+e.message,'error')}}
async function upload(file:File,title:string){const fd=new FormData();fd.append('file',file);fd.append('title',title);fd.append('tags','创意评估,用户上传');const r=await fetch('/api/creative/ai/assets/upload',{method:'POST',body:fd});if(!r.ok)throw new Error(await r.text());return await r.json()}
async function optimize3dPrompt(){if(!form3d.rawPrompt.trim()){emit('alert','请先填写基础3D模型描述','error');return}busy.value=true;startStage('正在调用 SiliconFlow · Qwen3，为 Tripo 文生3D整理优化提示词…');try{const r=await fetch('/api/creative/ai/prompt/tripo-3d-optimize',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({prompt:form3d.rawPrompt})});if(!r.ok){const err=await r.json().catch(()=>null);throw new Error(err?.message||`HTTP ${r.status}`)}const d=await r.json();form3d.prompt=d.prompt||'';emit('alert','Qwen3已优化Tripo 3D提示词，可继续人工修改','success')}catch(e:any){emit('alert','3D提示词优化失败：'+e.message,'error')}finally{busy.value=false;endStage()}}
async function upload3d(e:Event,view='single'){const f=(e.target as HTMLInputElement).files?.[0];if(!f)return;busy.value=true;try{const d=await upload(f,`3D建模${view==='single'?'参考图':view+'视图'}`);if(view==='single')form3d.inputAssetId=d.assetId;else (form3d.multiviewAssetIds as any)[view]=d.assetId;const r=await fetch(`/api/creative/ai/assets/${d.assetId}/content?v=${Date.now()}`,{cache:'no-store'});if(!r.ok)throw new Error(`参考图读取失败 HTTP ${r.status}`);const blob=await r.blob();if(tripoPreviews[view]?.startsWith('blob:'))URL.revokeObjectURL(tripoPreviews[view]);tripoPreviews[view]=URL.createObjectURL(blob);emit('alert','3D参考图已上传并显示','success')}catch(x:any){emit('alert','上传失败：'+x.message,'error')}finally{busy.value=false}}
async function generate3d(){if(!canGenerate3d.value){emit('alert',form3d.mode==='text_to_model'?'请填写模型描述':'请先上传所需参考图','error');return}syncTripoCompatibility();busy.value=true;modelResult.value=null;tripoProgress.value=0;tripoStatus.value=`正在提交 ${selected3dModelLabel.value} · ${tripoModeLabel.value}任务…`;try{const r=await fetch('/api/creative/ai/tripo/generate',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(form3d)});if(!r.ok){const err=await r.json().catch(()=>null);throw new Error(err?.message||`HTTP ${r.status}`)}const d=await r.json();emit('alert',`Tripo ${d.modelVersion||form3d.modelVersion}任务已提交，正在云端生成`,'success');await pollTripo(d.jobId)}catch(e:any){busy.value=false;tripoStatus.value='生成失败';emit('alert','Tripo 3D生成失败：'+e.message,'error')}}
async function pollTripo(jobId:number){clearTimeout(tripoTimer.value);try{const r=await fetch(`/api/creative/ai/tripo/tasks/${jobId}`,{cache:'no-store'});if(!r.ok){const err=await r.json().catch(()=>null);throw new Error(err?.message||`HTTP ${r.status}`)}const d=await r.json();tripoPollFailures.value=0;tripoProgress.value=Number(d.progress||0);tripoStatus.value=d.status==='succeeded'?'模型生成完成，文件已由后台自动下载到资产库':d.status==='failed'?`任务失败：${d.errorMessage||'未知错误'}`:`Tripo正在云端生成；后台服务会自动下载结果，关闭页面也不影响…`;if(d.status==='succeeded'){modelResult.value=d;busy.value=false;emit('alert','Tripo 3D模型生成完成并已自动下载','success');await load();return}if(d.status==='failed'){busy.value=false;throw new Error(d.errorMessage||'Tripo任务失败')}tripoTimer.value=setTimeout(()=>pollTripo(jobId),3000)}catch(e:any){tripoPollFailures.value++;if(tripoPollFailures.value<=20){tripoStatus.value=`页面查询暂时失败，后台仍会自动下载；正在重试（${tripoPollFailures.value}/20）…`;tripoTimer.value=setTimeout(()=>pollTripo(jobId),5000);return}busy.value=false;emit('alert','页面查询多次失败，但后台任务仍会继续：'+e.message,'error')}}
async function selectReviewImage(e:Event){const f=(e.target as HTMLInputElement).files?.[0];if(!f)return;busy.value=true;try{const d=await upload(f,reviewForm.title||'智能评估图片');reviewForm.assetId=d.assetId;uploadPreview.value=d.url;await prepareUploadPreview(d.assetId);emit('alert','评估图片已上传并显示','success')}catch(x:any){emit('alert','图片上传失败：'+x.message,'error')}finally{busy.value=false}}
async function evaluate(){if(!reviewForm.assetId){emit('alert','请先上传需要评估的产品图、设计稿或参考图','error');return}if(!reviewForm.copy.trim()){emit('alert','请填写产品创意文案或方案说明','error');return}busy.value=true;reviewResult.value=null;try{const context=`产品类型：${reviewForm.productType}
创意文案：${reviewForm.copy}
目标人群：${reviewForm.targetAudience}
预期价格：${reviewForm.priceRange}
材质工艺：${reviewForm.material}
销售场景：${reviewForm.salesScene}
生产要求：${reviewForm.productionRequirement}
爆款/竞品参考：${reviewForm.hotReference}
竞品价格：${reviewForm.competitorPrice}
竞品销量/热度：${reviewForm.competitorSales}
计划渠道：${reviewForm.channelPlan}
目标成本：${reviewForm.targetCost}
预估首批销量：${reviewForm.expectedVolume}
请按三个阶段完善评估：第一阶段结构化评分和风险标签；第二阶段爆款/竞品对标、渠道和价格带分析；第三阶段给出进入BOM成本核算、打样和小批量试销的落地路线。`;const r=await fetch('/api/creative/ai/reviews',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({assetId:reviewForm.assetId,context})});if(!r.ok)throw new Error(await r.text());reviewResult.value=await r.json();emit('alert','智能可行性评估完成','success');await load()}catch(e:any){emit('alert','评估失败：'+e.message,'error')}finally{busy.value=false}}


function openHistoryReport(r:any){reviewResult.value=r;showReviewDetail.value=true;emit('alert','已打开历史评估报告','success')}
function reviewDate(x:any){return x?.createdAt?String(x.createdAt).replace('T',' ').slice(0,16):''}
function printReviewReport(){setTimeout(()=>window.print(),50)}
function recommendationText(v:any){return v==='go'?'建议进入产品开发':v==='adjust'?'优化后进入开发':'暂缓立项'}
function scoreClass(n:any){return Number(n)>=85?'good':Number(n)>=70?'warn':'bad'}
onMounted(()=>{active.value=props.initialView;load()});onBeforeUnmount(()=>{clearInterval(stageTimer.value);clearTimeout(tripoTimer.value);clearTimeout(tripoImageTimer.value);if(imagePreviewUrl.value.startsWith('blob:'))URL.revokeObjectURL(imagePreviewUrl.value);if(uploadPreviewUrl.value.startsWith('blob:'))URL.revokeObjectURL(uploadPreviewUrl.value);Object.values(tripoPreviews).forEach(x=>{if(x.startsWith('blob:'))URL.revokeObjectURL(x)})})
</script>
<template><div class="page creative-page">
<section v-if="active==='image2d'" class="workspace premium-workspace two-d-workspace"><div class="card premium-card control-panel"><div class="panel-heading"><div class="panel-mark violet">2D</div><div><span class="panel-eyebrow">TRIPO · CREATIVE RENDER</span><h3>文本创意生成</h3><p>Qwen3整理创意意图，Tripo完成商业级视觉输出。</p></div><div class="live-badge"><i></i>API V3</div></div><div class="service-strip"><div><small>AVAILABLE CREDITS</small><strong>{{tripoConfig.balance??0}}</strong></div><div><small>ENGINE</small><b>{{form2d.tripoImageModel}}</b></div><div><small>DELIVERY</small><b>自动保存</b></div></div><div class="workflow-block"><header><span>01</span><div><b>创意输入</b><small>使用自然语言描述主体与视觉方向</small></div></header><textarea rows="4" v-model="form2d.rawPrompt" placeholder="例如：一款面向年轻游客的山城街巷主题文创钥匙扣，温暖治愈、精致高级……"></textarea><button class="btn ai-action" :disabled="busy||!form2d.rawPrompt.trim()" @click="compose"><span>Q3</span>{{busy&&aiStage.includes('Qwen3')?'Qwen3 正在重构创意…':'使用 Qwen3 优化提示词'}}</button></div><div class="workflow-block"><header><span>02</span><div><b>生成提示词</b><small>可在提交前进行人工精修</small></div></header><textarea rows="6" v-model="generatedPrompt" placeholder="Qwen3优化后的Prompt将显示在这里"></textarea></div><div class="workflow-block compact"><header><span>03</span><div><b>官方生成参数</b><small>仅保留Tripo API支持字段</small></div></header><div class="grid parameter-grid"><label>MODEL<select v-model="form2d.tripoImageModel"><option value="seedream_v5">seedream_v5</option><option value="seedream_v4">seedream_v4</option><option value="banana">banana</option><option value="banana_pro">banana_pro</option><option value="banana2">banana2</option><option value="chat_image_1">chat_image_1</option><option value="chat_image_1.5">chat_image_1.5</option><option value="chat_image_2">chat_image_2</option></select></label><label>TEMPLATE<select v-model="form2d.tripoTemplate"><option value="">不设置</option><option value="asset_extraction">asset_extraction</option><option value="character_completion">character_completion</option><option value="t_pose">t_pose</option><option value="head_extraction">head_extraction</option><option value="3d_enhance">3d_enhance</option><option value="variants">variants</option><option value="print_clay">print_clay</option><option value="figure">figure</option></select></label></div><div class="official-toggles"><button type="button" :class="{active:form2d.tPose}" @click="form2d.tPose=!form2d.tPose"><b>T-POSE</b><span>正面角色姿态</span><em>{{form2d.tPose?'ON':'OFF'}}</em></button><button type="button" :class="{active:form2d.sketchToRender}" @click="form2d.sketchToRender=!form2d.sketchToRender"><b>SKETCH RENDER</b><span>草图转渲染模式</span><em>{{form2d.sketchToRender?'ON':'OFF'}}</em></button></div><details class="payload-preview"><summary>查看API请求参数</summary><code>{{JSON.stringify({model:form2d.tripoImageModel,template:form2d.tripoTemplate||undefined,t_pose:form2d.tPose||undefined,sketch_to_render:form2d.sketchToRender||undefined},null,2)}}</code></details></div><div v-if="aiStage" class="ai-progress premium-progress"><span class="spinner"></span><div><b>{{aiStage}}</b><small>已运行 {{elapsed}} 秒 · 后台任务不会因关闭页面中断</small></div></div><button class="btn btn-primary full launch-btn" :disabled="busy||!generatedPrompt.trim()||Number(tripoConfig.balance||0)<=0" @click="generate2d"><span>{{busy?'PROCESSING':'GENERATE'}}</span>{{busy?'Tripo 正在生成视觉资产…':`使用 ${form2d.tripoImageModel} 开始生成`}}</button></div><div ref="resultAnchor" class="card premium-card result preview-panel"><div class="panel-heading result-heading"><div><span class="panel-eyebrow">LIVE OUTPUT</span><h3>视觉输出</h3></div><span class="asset-state" :class="{ready:imageResult}">{{imageResult?'READY':'STANDBY'}}</span></div><div class="result-canvas" :class="{hasResult:imageResult}"><div v-if="imageResult" class="image-result"><img v-if="imageSrc(imageResult)" :key="imagePreviewUrl||imageResult.assetId" :src="imageSrc(imageResult)"><div v-if="imageLoadError" class="image-error">{{imageLoadError}} <button @click="prepareImagePreview(imageResult)">重新加载</button></div><div class="output-meta"><div><b>Tripo视觉资产</b><small>{{imageResult.source||form2d.tripoImageModel}}</small></div><code>{{imageResult.jobNo}}</code></div></div><div v-else class="premium-empty"><div class="empty-orbit"><span>2D</span></div><b>等待生成视觉资产</b><p>完成创意描述和参数设置后，输出将在此处实时呈现并进入资产库。</p></div></div></div></section>
<section v-if="active==='model3d'" class="model-workspace"><div class="tripo-workbench premium-workspace"><div class="card premium-card form-card"><div class="panel-heading"><div class="panel-mark cyan">3D</div><div><span class="panel-eyebrow">TRIPO · MODEL PIPELINE</span><h3>3D建模工作台</h3><p>模型与质量均可按Tripo平台当前提供范围选择；文生3D支持Qwen3提示词优化。</p></div><div class="live-badge"><i></i>API V3</div></div><div class="tripo-account-bar"><div class="connection-dot" :class="{online:tripoConfigured&&tripoConfig.serviceReachable}"></div><div><small>TRIPO API V3</small><b>{{tripoConfigured&&tripoConfig.serviceReachable?'服务已连接':'服务未连接'}}</b></div><div class="connected-model"><small>当前连接模型</small><b>{{selected3dModelLabel}}</b><code>{{form3d.modelVersion}}</code></div><div class="credit-box"><small>API可用积分</small><strong>{{tripoConfig.balance??'--'}}</strong><span>冻结 {{tripoConfig.frozenBalance??0}}</span></div></div><div v-if="!tripoConfigured||!tripoConfig.serviceReachable" class="credit-warning"><b>Tripo连接异常</b><span>{{tripoConfig.connectionError||'请检查API Key和服务器外网'}}</span></div><div class="model-choice"><div class="choice-head"><div><b>选择3D模型</b><span>点击模型卡片后，上方“当前连接模型”会立即更新</span></div><em>当前：{{form3d.modelVersion}}</em></div><div class="series-group p-series"><div class="series-title"><b>P SERIES</b><span>低面数、干净拓扑、游戏和移动端资产</span></div><div class="model-cards"><button v-for="m in available3dModels.filter((x:any)=>x.series==='P')" :key="m.value" type="button" :disabled="busy" :class="{active:form3d.modelVersion===m.value}" @click="select3dModel(m.value)"><span class="model-tag">{{m.tag}}</span><b>{{m.label}}</b><code>{{m.value}}</code><em>{{form3d.modelVersion===m.value?'已连接':'点击选择'}}</em></button></div></div><div class="series-group h-series"><div class="series-title"><b>H SERIES</b><span>高精度几何、产品展示、3D打印与生产资产</span></div><div class="model-cards"><button v-for="m in available3dModels.filter((x:any)=>x.series==='H')" :key="m.value" type="button" :disabled="busy" :class="{active:form3d.modelVersion===m.value}" @click="select3dModel(m.value)"><span class="model-tag">{{m.tag}}</span><b>{{m.label}}</b><code>{{m.value}}</code><em>{{form3d.modelVersion===m.value?'已连接':'点击选择'}}</em></button></div></div></div><div class="model-hint" :class="{p1:isP1,legacy:isLegacy25}"><b>{{isP1?'P系列低面数模型':isLegacy25?'v2.5兼容模型':'H系列高精度模型'}}</b><span>{{isP1?'面数48–20,000，不支持四边面、智能低模、可分离部件和Geometry Quality。':isLegacy25?'最高500,000面，不支持v3高级质量与拓扑参数。':'支持Geometry Quality、最高200万面、四边面、智能低模与可分离部件。'}}</span></div><div class="mode-tabs"><button v-for="m in [{v:'image_to_model',n:'单图生3D'},{v:'multiview_to_model',n:'多视图生3D'},{v:'text_to_model',n:'文生3D'}]" :key="m.v" :class="{active:form3d.mode===m.v}" @click="form3d.mode=m.v">{{m.n}}</button></div><template v-if="form3d.mode==='image_to_model'"><label class="upload"><input type="file" accept="image/png,image/jpeg,image/webp" @change="upload3d($event,'single')"><span>{{form3d.inputAssetId?'参考图已上传，可重新选择':'上传单张产品图 / 设计图'}}</span></label><img v-if="tripoPreviews.single" :src="tripoPreviews.single" class="preview"></template><template v-else-if="form3d.mode==='multiview_to_model'"><div class="multiview-grid"><label v-for="v in [{k:'front',n:'正面（必传）'},{k:'left',n:'左侧'},{k:'back',n:'背面'},{k:'right',n:'右侧'}]" :key="v.k" class="view-upload"><input type="file" accept="image/png,image/jpeg,image/webp" @change="upload3d($event,v.k)"><img v-if="tripoPreviews[v.k]" :src="tripoPreviews[v.k]"><span v-else>＋ {{v.n}}</span><b>{{v.n}}</b></label></div><small class="field-tip">至少正面图和另一个视角，共2张；建议上传正、左、背、右4张。</small></template><template v-else><label>基础3D模型描述（Qwen3输入）<textarea rows="4" v-model="form3d.rawPrompt" placeholder="描述主体、结构、材质、部件和用途"></textarea></label><button class="btn full" :disabled="busy||!form3d.rawPrompt.trim()" @click="optimize3dPrompt">{{busy&&aiStage.includes('文生3D')?'Qwen3 正在优化…':'调用 Qwen3 整理优化3D提示词'}}</button><label>Prompt<textarea rows="6" v-model="form3d.prompt" placeholder="Qwen3优化后的Tripo Prompt，可人工修改"></textarea></label><label>Negative Prompt<textarea rows="2" v-model="form3d.negativePrompt"></textarea></label></template><div v-if="aiStage&&form3d.mode==='text_to_model'" class="ai-progress"><span class="spinner"></span><div><b>{{aiStage}}</b><small>已等待 {{elapsed}} 秒</small></div></div><details class="advanced" open><summary>Tripo官方生成参数</summary><div class="option-grid"><label v-if="!isLegacy25">Texture Quality<select v-model="form3d.textureQuality" :disabled="!form3d.texture"><option value="standard">standard</option><option value="detailed">detailed</option><option value="extreme">extreme</option></select></label><label v-if="supportsAdvanced3d">Geometry Quality<select v-model="form3d.geometryQuality"><option value="standard">standard</option><option value="detailed">detailed / Ultra</option></select></label><label v-if="form3d.mode==='image_to_model'||isP1&&form3d.mode==='multiview_to_model'">模型朝向<select v-model="form3d.orientation"><option value="align_image">align_image</option><option value="default">default</option></select></label><label v-if="form3d.mode==='image_to_model'||isP1&&form3d.mode==='multiview_to_model'">纹理对齐<select v-model="form3d.textureAlignment" :disabled="!form3d.texture"><option value="original_image">original_image</option><option value="geometry">geometry</option></select></label><label>Face Limit<input type="number" :min="isP1?48:1000" :max="max3dFaces" step="1000" v-model.number="form3d.faceLimit" @change="syncTripoCompatibility"></label><label v-if="form3d.mode==='text_to_model'||isP1">Model Seed<input type="number" v-model.number="form3d.modelSeed" placeholder="留空随机"></label><label v-if="form3d.mode==='text_to_model'">Image Seed<input type="number" v-model.number="form3d.imageSeed" placeholder="留空随机"></label><label>Texture Seed<input type="number" v-model.number="form3d.textureSeed" :disabled="!form3d.texture" placeholder="留空随机"></label><label>输出格式<input :value="form3d.quad?'FBX':'GLB'" disabled></label></div><div class="switch-grid"><label><input type="checkbox" v-model="form3d.texture" @change="syncTripoCompatibility">Texture<span>生成纹理</span></label><label><input type="checkbox" v-model="form3d.pbr" :disabled="!form3d.texture">PBR<span>材质贴图</span></label><label v-if="form3d.mode==='image_to_model'"><input type="checkbox" v-model="form3d.imageAutofix">Image Autofix<span>自动修复图片</span></label><label v-if="!isLegacy25"><input type="checkbox" v-model="form3d.autoSize">Auto Size<span>真实尺寸</span></label><label><input type="checkbox" v-model="form3d.exportUv">Export UV<span>UV展开</span></label><label v-if="!isLegacy25"><input type="checkbox" v-model="form3d.compress">Compress<span>meshopt</span></label><label v-if="supportsAdvanced3d"><input type="checkbox" v-model="form3d.quad" @change="syncTripoCompatibility">Quad<span>最高15万面 / FBX</span></label><label v-if="supportsAdvanced3d"><input type="checkbox" v-model="form3d.smartLowPoly" @change="syncTripoCompatibility">Smart Low Poly<span>最高2万面</span></label><label v-if="supportsAdvanced3d"><input type="checkbox" v-model="form3d.generateParts" @change="syncTripoCompatibility">Generate Parts<span>可编辑分段部件</span></label></div></details><div v-if="busy&&tripoStatus" class="tripo-progress"><div><b>{{tripoStatus}}</b><span>{{tripoProgress}}%</span></div><progress v-if="tripoProgress>0" :value="tripoProgress" max="100"></progress><progress v-else></progress><small>服务器后台会持续查询并自动下载，关闭页面不影响任务。</small></div><button class="btn btn-primary full" :disabled="busy||!canGenerate3d||!tripoConfigured||!tripoConfig.serviceReachable||Number(tripoConfig.balance||0)<=0" @click="generate3d">{{busy?'Tripo 正在生成…':`使用 ${form3d.modelVersion} 生成 · ${tripoModeLabel}`}}</button></div><div class="card premium-card result model-output"><div class="panel-heading result-heading"><div><span class="panel-eyebrow">MODEL OUTPUT</span><h3>3D模型输出</h3></div><span class="asset-state" :class="{ready:modelResult}">{{modelResult?'READY':'STANDBY'}}</span></div><template v-if="modelResult"><img v-if="modelResult.previewUrl" :src="modelResult.previewUrl" class="preview model-preview"><div class="model-success"><b>Tripo模型生成成功</b><span>模型：{{form3d.modelVersion}} · 格式：{{modelResult.format?.toUpperCase()||'GLB'}} · 任务：{{modelResult.taskId}}</span><a class="btn btn-primary" :href="modelResult.modelUrl" download>下载3D模型</a></div><div class="viewer-tip">模型由服务器后台自动下载并保存到系统资产库。</div></template><div v-else class="empty tall">选择Tripo模型、生成方式和官方参数后提交。文生3D可先用Qwen3整理Prompt。</div></div></div><section class="card premium-card model-library"><header><div><h3>已生成3D模型</h3><p>模型文件和预览图已保存到服务器及系统资产库，刷新或重新登录后仍会保留。</p></div><b>{{modelAssets.length}} 个模型</b></header><div v-if="modelAssets.length" class="saved-model-grid"><article v-for="a in modelAssets" :key="a.id" :class="{active:modelResult?.assetId===a.id}" @click="showSavedModel(a)"><div class="saved-preview"><img v-if="a.previewUrl" :src="a.previewUrl"><span v-else>3D</span></div><div class="saved-info"><b>{{a.title}}</b><small>{{a.assetNo}} · {{a.format?.toUpperCase()}}</small><time>{{String(a.createdAt||'').replace('T',' ')}}</time><div><button type="button" @click.stop="showSavedModel(a)">查看</button><a :href="a.fileUrl" download @click.stop>下载模型</a></div></div></article></div><div v-else class="empty">暂无已生成模型；任务完成后会自动出现在这里并永久保留。</div></section></section>
<section v-if="active==='review'" class="review-workspace"><div class="workspace premium-workspace review-grid"><div class="card premium-card form-card"><div class="panel-heading"><div class="panel-mark emerald">AI</div><div><span class="panel-eyebrow">COMMERCIAL FEASIBILITY LAB</span><h3>智能可行性评估</h3><p>从设计、市场、成本与消费转化四个维度完成商业评审。</p></div><div class="live-badge teal"><i></i>MULTI AGENT</div></div><div class="review-submenu"><button :class="{active:reviewSubTab==='new'}" @click="reviewSubTab='new'">新建评估</button><button :class="{active:reviewSubTab==='history'}" @click="reviewSubTab='history'">历史评估 <em>{{reviews.length}}</em></button></div><div v-if="reviewSubTab==='history'" class="history-panel"><header><div><span>REPORT ARCHIVE</span><h3>历史评估</h3><p>所有生成过的智能评估报告都会自动留存，点击即可打开横屏报告单。</p></div></header><div class="history-list"><button v-for="r in reviews" :key="r.reviewNo||r.id" @click="openHistoryReport(r)"><strong :class="scoreClass(r.overallScore)">{{r.overallScore}}</strong><div><b>{{r.assetTitle||r.asset?.title||r.reviewNo}}</b><small>{{r.reviewNo}} · {{reviewDate(r)}}</small><p>{{r.summary}}</p></div><i>查看报告</i></button></div><div v-if="!reviews.length" class="history-empty"><b>暂无历史评估</b><p>完成一次智能评估后，报告会自动出现在这里。</p></div></div><template v-if="reviewSubTab==='new'"><label class="upload premium-upload large"><input type="file" accept="image/png,image/jpeg,image/webp" @change="selectReviewImage"><span class="upload-icon">＋</span><b>{{reviewForm.assetId?'评估图片已就绪':'上传产品图片 / 设计稿 / 包装图'}}</b><small>{{reviewForm.assetId?'点击可重新选择文件':'PNG · JPG · WEBP'}}</small></label><img v-if="uploadPreview&&reviewForm.assetId" :src="uploadPreviewUrl||uploadPreview" class="preview review-preview"><div v-if="uploadLoadError" class="image-error">{{uploadLoadError}} <button @click="prepareUploadPreview(reviewForm.assetId!)">自动重试</button></div><div class="form-section-title"><span>01</span><b>商业基础信息</b></div><div class="grid commercial-grid"><label>方案名称<input v-model="reviewForm.title"></label><label>产品类型<input v-model="reviewForm.productType"></label><label>目标人群<input v-model="reviewForm.targetAudience"></label><label>价格区间<input v-model="reviewForm.priceRange" placeholder="如 39–69元"></label><label>材质工艺<input v-model="reviewForm.material"></label><label>销售场景<input v-model="reviewForm.salesScene"></label><label>计划渠道<input v-model="reviewForm.channelPlan" placeholder="景区/小红书/抖音/礼品店"></label><label>目标成本<input v-model="reviewForm.targetCost" placeholder="如 单件12元内"></label></div><div class="form-section-title"><span>02</span><b>爆款/竞品对标</b></div><label>原有爆款或竞品参考<textarea rows="3" v-model="reviewForm.hotReference" placeholder="可填写爆款名称、链接、图片特征、卖点、用户评价、可借鉴点"></textarea></label><div class="grid commercial-grid"><label>竞品价格<input v-model="reviewForm.competitorPrice" placeholder="如 29/39/59元"></label><label>销量/热度<input v-model="reviewForm.competitorSales" placeholder="如 月销1万+、收藏高"></label><label>预估首批销量<input v-model="reviewForm.expectedVolume" placeholder="如 300/1000件"></label></div><div class="form-section-title"><span>03</span><b>方案与生产要求</b></div><label>创意文案 / 产品方案<textarea rows="5" v-model="reviewForm.copy" placeholder="产品故事、核心卖点、文化元素、设计表达与使用方式"></textarea></label><label>生产与质量要求<textarea rows="3" v-model="reviewForm.productionRequirement" placeholder="材料、工艺、包装、质检或交付要求"></textarea></label><button class="btn btn-primary full launch-btn review-launch" :disabled="busy" @click="evaluate"><span>{{busy?'ANALYZING':'START REVIEW'}}</span>{{busy?'多角色智能评审进行中…':'启动商业级多角色评估'}}</button></template></div><div class="card premium-card result review-result"><div class="panel-heading result-heading"><div><span class="panel-eyebrow">AI REVIEW REPORT</span><h3>商业评审报告</h3></div><span class="asset-state" :class="{ready:reviewResult}">{{reviewResult?'COMPLETE':'STANDBY'}}</span></div><template v-if="reviewResult"><div class="score-head premium-score"><div :class="['score',scoreClass(reviewResult.overallScore)]">{{reviewResult.overallScore}}</div><div><span class="score-label">OVERALL SCORE</span><h3>{{recommendationText(reviewResult.recommendation)}}</h3><p>{{reviewResult.summary}}</p><p v-if="reviewResult.roadmap"><b>决策：</b>{{reviewResult.roadmap.decision}}</p><div class="report-actions"><button class="btn" @click="showReviewDetail=true">查看详细评估报告</button><button class="btn" @click="printReviewReport">打印/导出报告</button></div></div></div><div v-if="reviewResult.matrix" class="matrix-grid"><div v-for="(v,k) in reviewResult.matrix" :key="k"><b>{{k}}</b><span>{{v}}</span><progress max="100" :value="Number(v)"></progress></div></div><Teleport to="body"><div v-if="showReviewDetail" class="report-modal"><div class="report-modal-mask" @click="showReviewDetail=false"></div><div class="report-modal-panel"><div class="report-toolbar"><b>详细评估报告单</b><div><button @click="printReviewReport">打印/导出PDF</button><button @click="showReviewDetail=false">关闭</button></div></div><div class="review-report-sheet landscape-report"><header><div><small>AI COMMERCIAL REVIEW</small><h2>文创产品智能评估报告单</h2><p>{{reviewForm.title}} · {{reviewForm.productType}}</p></div><strong :class="scoreClass(reviewResult.overallScore)">{{reviewResult.overallScore}}</strong></header><div class="report-kpis"><div><span>产品类型</span><b>{{reviewForm.productType}}</b></div><div><span>价格区间</span><b>{{reviewForm.priceRange||'待定'}}</b></div><div><span>目标渠道</span><b>{{reviewForm.channelPlan||'待定'}}</b></div><div><span>建议结论</span><b>{{recommendationText(reviewResult.recommendation)}}</b></div></div><section class="report-section"><h3>一、五维评分雷达</h3><div class="report-bars"><div v-for="(v,k) in reviewResult.matrix" :key="k"><label><b>{{k}}</b><em>{{v}}</em></label><progress max="100" :value="Number(v)"></progress></div></div></section><section class="report-section"><h3>二、三阶段升级方案</h3><div class="report-columns"><article><b>阶段 1：结构化评估</b><ul><li v-for="x in reviewResult.roadmap?.phase1">{{x}}</li></ul></article><article><b>阶段 2：爆款/竞品对标</b><ul><li v-for="x in reviewResult.roadmap?.phase2">{{x}}</li></ul></article><article><b>阶段 3：生产商业闭环</b><ul><li v-for="x in reviewResult.roadmap?.phase3">{{x}}</li></ul></article></div></section><section class="report-section"><h3>三、多角色详细意见</h3><div class="report-agent-grid"><article v-for="a in reviewResult.agents" :key="a.agentKey"><header><b>{{a.agentName}}</b><em :class="scoreClass(a.score)">{{a.score}}</em></header><p>{{a.comments}}</p><p v-if="a.benchmark"><b>爆款对标：</b>{{a.benchmark}}</p><ul><li v-for="x in a.suggestions">{{x}}</li></ul></article></div></section><section v-if="reviewResult.roadmap?.risks?.length" class="report-section"><h3>四、风险与处理建议</h3><div class="risk-table"><p v-for="r in reviewResult.roadmap.risks"><span>{{r.level}}</span><b>{{r.name}}</b><em>{{r.advice}}</em></p></div></section><footer>本报告由 AI 多角色评审生成，用于立项、改版、打样和成本核算前的辅助决策。</footer></div></div></div></Teleport><div v-if="reviewResult.roadmap" class="roadmap"><section><b>第一阶段 · 结构化评估</b><ul><li v-for="x in reviewResult.roadmap.phase1">{{x}}</li></ul></section><section><b>第二阶段 · 爆款对标</b><ul><li v-for="x in reviewResult.roadmap.phase2">{{x}}</li></ul></section><section><b>第三阶段 · 生产闭环</b><ul><li v-for="x in reviewResult.roadmap.phase3">{{x}}</li></ul></section></div><div v-if="reviewResult.roadmap?.risks?.length" class="risk-box"><b>风险雷达</b><p v-for="r in reviewResult.roadmap.risks"><em>{{r.level}}</em>{{r.name}}：{{r.advice}}</p></div><div class="agent-list"><div v-for="a in reviewResult.agents" :key="a.agentKey" class="agent premium-agent"><header><div><span>AI REVIEWER</span><b>{{a.agentName}}</b></div><em :class="scoreClass(a.score)">{{a.score}} · {{a.verdict}}</em></header><p>{{a.comments}}</p><small v-if="a.benchmark">爆款对标：{{a.benchmark}}</small><ul><li v-for="x in a.suggestions">{{x}}</li></ul></div></div></template><div v-else class="premium-empty review-empty"><div class="review-dimensions"><span>设计</span><span>市场</span><span>成本</span><span>转化</span></div><b>等待商业评估</b><p>提交完整资料后，AI评审团将输出可执行的评分、风险结论与优化建议。</p></div></div></div></section>
